/**
 * @name Taint flow from method parameters to git command execution in CliGitAPIImpl
 * @description Find paths where method parameters flow to git command arguments
 * @kind path-problem
 * @problem.severity error
 * @id java/git-client-argument-injection
 * @tags security
 *       external/cwe/cwe-078
 *       external/cwe/cwe-088
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module GitArgInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Parameters of public methods in CliGitAPIImpl that accept user-controlled strings
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "CliGitAPIImpl") and
      p.getCallable().(Method).isPublic() and
      (p.getType() instanceof TypeString or p.getType().hasName("URIish")) and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Arguments added to command builders in CliGitAPIImpl
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "CliGitAPIImpl") and
      mc.getMethod().hasName("add") and
      mc.getMethod().getDeclaringType().hasQualifiedName("hudson.util", "ArgumentListBuilder") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // launchCommandIn direct args
    exists(MethodCall mc |
      mc.getMethod().hasName("launchCommandIn") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "CliGitAPIImpl") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module GitArgInjectionFlow = TaintTracking::Global<GitArgInjectionConfig>;
import GitArgInjectionFlow::PathGraph

from GitArgInjectionFlow::PathNode source, GitArgInjectionFlow::PathNode sink
where GitArgInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Git argument injection: $@ flows to command argument.", source.getNode(), "user-controlled parameter"

/**
 * @name Missing option terminator '--' before user-controlled git arguments
 * @description Git commands that add user-controlled values without preceding '--' separator allow flag injection
 * @kind problem
 * @problem.severity error
 * @id java/git-missing-option-terminator
 * @tags security
 *       external/cwe/cwe-088
 */

import java
import semmle.code.java.dataflow.TaintTracking

module FlagInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "CliGitAPIImpl") and
      p.getCallable().(Method).isPublic() and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "CliGitAPIImpl") and
      mc.getMethod().hasName("add") and
      mc.getMethod().getDeclaringType().hasQualifiedName("hudson.util", "ArgumentListBuilder") and
      sink.asExpr() = mc.getAnArgument() and
      // Check that there's no "--" terminator added before this argument
      not exists(MethodCall prevAdd |
        prevAdd.getMethod().hasName("add") and
        prevAdd.getMethod().getDeclaringType().hasQualifiedName("hudson.util", "ArgumentListBuilder") and
        prevAdd.getAnArgument().(StringLiteral).getValue() = "--" and
        prevAdd.getEnclosingCallable() = mc.getEnclosingCallable() and
        prevAdd.getLocation().getStartLine() < mc.getLocation().getStartLine()
      )
    )
  }
}

module FlagInjectionFlow = TaintTracking::Global<FlagInjectionConfig>;

from DataFlow::Node source, DataFlow::Node sink
where FlagInjectionFlow::flow(source, sink)
select sink, "User-controlled value '" + source.asParameter().getName() + "' from method '" + source.asParameter().getCallable().getName() + "' added to git command without '--' option terminator at line " + sink.asExpr().getLocation().getStartLine()

/**
 * @name Environment variable injection in git command execution
 * @description User-controlled values set as environment variables that affect git behavior
 * @kind problem
 * @problem.severity error
 * @id java/git-env-var-injection
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking

// Look for env var manipulation in CliGitAPIImpl where user data flows to environment map
module EnvVarInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "CliGitAPIImpl") and
      p.getCallable().(Method).isPublic() and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Env map put operations
    exists(MethodCall mc |
      mc.getMethod().hasName("put") and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "CliGitAPIImpl") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // hudson.EnvVars operations
    exists(MethodCall mc |
      (mc.getMethod().hasName("override") or mc.getMethod().hasName("putAll")) and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "CliGitAPIImpl") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module EnvVarInjectionFlow = TaintTracking::Global<EnvVarInjectionConfig>;

from DataFlow::Node source, DataFlow::Node sink
where EnvVarInjectionFlow::flow(source, sink)
select sink, "User-controlled value from '" + source.asParameter().getCallable().getName() + 
  "' param '" + source.asParameter().getName() + "' flows to environment variable at line " + 
  sink.asExpr().getLocation().getStartLine()

/**
 * @name Git client argument injection - comprehensive summary
 * @description Comprehensive detection of all argument injection vulnerabilities in CliGitAPIImpl
 * @kind problem
 * @problem.severity error
 * @id java/git-client-arg-injection-summary
 * @tags security
 *       external/cwe/cwe-078
 *       external/cwe/cwe-088
 */

import java
import semmle.code.java.dataflow.TaintTracking

module ComprehensiveConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(Parameter p |
      (
        p.getCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "CliGitAPIImpl") or
        p.getCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "LegacyCompatibleGitAPIImpl")
      ) and
      p.getCallable().(Method).isPublic() and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Direct add to ArgumentListBuilder
    exists(MethodCall mc |
      (
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "CliGitAPIImpl") or
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "LegacyCompatibleGitAPIImpl")
      ) and
      mc.getMethod().hasName("add") and
      mc.getMethod().getDeclaringType().hasQualifiedName("hudson.util", "ArgumentListBuilder") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ComprehensiveFlow = TaintTracking::Global<ComprehensiveConfig>;

// Group by source method for a cleaner summary
from DataFlow::Node source, DataFlow::Node sink
where 
  ComprehensiveFlow::flow(source, sink) and
  // Focus on the most security-relevant methods
  source.asParameter().getCallable().(Method).getName() in [
    "getHeadRev", "getRemoteReferences", "getRemoteSymbolicReferences",
    "getRemoteTagNames", "getTagNames", "push", "revList",
    "setAuthor", "setCommitter", "addCredentials"
  ]
select sink,
  "[CWE-088] Method '" + source.asParameter().getCallable().getName() + 
  "' param '" + source.asParameter().getName() + 
  "' -> git cmd arg at line " + sink.asExpr().getLocation().getStartLine() +
  " (expr: " + sink.asExpr().toString() + ")"

/**
 * @name getHeadRev branchSpec injection - string concat in git ls-remote command
 * @description The branchSpec parameter in getHeadRev is concatenated into a git command argument
 * @kind problem
 * @problem.severity error
 * @id java/git-headrev-branchspec-injection
 * @tags security
 *       external/cwe/cwe-078
 *       external/cwe/cwe-088
 */

import java
import semmle.code.java.dataflow.TaintTracking

// Find all binary string concatenation expressions passed as arguments to add()
// where a method parameter is involved
module BranchInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "CliGitAPIImpl") and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.gitclient", "CliGitAPIImpl") and
      mc.getMethod().hasName("add") and
      mc.getMethod().getDeclaringType().hasQualifiedName("hudson.util", "ArgumentListBuilder") and
      sink.asExpr() = mc.getAnArgument() and
      // The argument is a binary concatenation expression
      mc.getAnArgument() instanceof BinaryExpr
    )
  }
}

module BranchInjectionFlow = TaintTracking::Global<BranchInjectionConfig>;

from DataFlow::Node source, DataFlow::Node sink
where BranchInjectionFlow::flow(source, sink)
select sink,
  "Parameter '" + source.asParameter().getName() + "' from method '" + 
  source.asParameter().getCallable().getName() + 
  "' is concatenated into git command argument at line " + 
  sink.asExpr().getLocation().getStartLine()
